const AllVariants = () => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
    <Alert variant="info" title="Information">This is an informational alert for general notices.</Alert>
    <Alert variant="success" title="Success">Action completed successfully. Changes have been saved.</Alert>
    <Alert variant="warning" title="Warning">Please review your input. Some fields may need attention.</Alert>
    <Alert variant="error" title="Error">Something went wrong. Please try again or contact support.</Alert>
  </div>
);

const AllVariants = () => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
    <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
      <span style={{ width: 50, fontSize: 13, color: '#6F7285' }}>Solid</span>
      {(['default', 'primary', 'accent', 'success', 'warning', 'error', 'info'] as const).map((v) => (
        <Badge key={v} variant={v} style_type="solid">{v}</Badge>
      ))}
    </div>
    <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
      <span style={{ width: 50, fontSize: 13, color: '#6F7285' }}>Subtle</span>
      {(['default', 'primary', 'accent', 'success', 'warning', 'error', 'info'] as const).map((v) => (
        <Badge key={v} variant={v} style_type="subtle">{v}</Badge>
      ))}
    </div>
    <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
      <span style={{ width: 50, fontSize: 13, color: '#6F7285' }}>Outline</span>
      {(['default', 'success', 'warning', 'error', 'info'] as const).map((v) => (
        <Badge key={v} variant={v} style_type="outline">{v}</Badge>
      ))}
    </div>
  </div>
);

const Sizes = () => (
  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
    <Button size="sm">Small</Button>
    <Button size="md">Medium</Button>
    <Button size="lg">Large</Button>
  </div>
);

const AllVariants = () => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
    {(['primary', 'secondary', 'accent', 'ghost', 'danger'] as const).map((v) => (
      <div key={v} style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
        <span style={{ width: 80, fontSize: 13, color: '#6F7285' }}>{v}</span>
        <Button variant={v}>Default</Button>
        <Button variant={v} disabled>Disabled</Button>
      </div>
    ))}
  </div>
);

const AllStates = () => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
    <Checkbox label="Unchecked" />
    <Checkbox label="Checked" defaultChecked />
    <Checkbox label="Disabled" disabled />
    <Checkbox label="Checked Disabled" defaultChecked disabled />
  </div>
);

const AllStates = () => (
  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 300px)', gap: 24 }}>
    <Input label="Default" placeholder="Placeholder text" />
    <Input label="With Value" defaultValue="Typing here..." />
    <Input label="Error" defaultValue="Invalid input" error="This field is required" />
    <Input label="Success" defaultValue="Valid input" success="Looks good!" />
    <Input label="Disabled" placeholder="Cannot edit" disabled />
  </div>
);

const Simple = () => (
  <ListGroup>
    <ListItem title="Dashboard" />
    <ListItem title="Analytics" active />
    <ListItem title="Settings" />
    <ListItem title="Profile" />
  </ListGroup>
);

const WithDescription = () => (
  <ListGroup>
    <ListItem title="Notifications" description="Manage your notification preferences" trailing="›" />
    <ListItem title="Privacy" description="Control your privacy and security" trailing="›" />
    <ListItem title="Appearance" description="Customize the look and feel" trailing="›" />
  </ListGroup>
);

